import json
import matplotlib
matplotlib.use('Agg')  # Non-interactive backend for headless execution
import matplotlib.pyplot as plt
import numpy as np
from pathlib import Path
from config import get_processed_data_dir, get_figures_dir

def load_power_analysis_results():
    """Load the power analysis results from the JSON file generated by T009."""
    data_dir = get_processed_data_dir()
    input_path = data_dir / "power_analysis_results.json"
    
    if not input_path.exists():
        raise FileNotFoundError(
            f"Power analysis results file not found at {input_path}. "
            "Please ensure T009 has been completed successfully."
        )
    
    with open(input_path, 'r') as f:
        return json.load(f)

def generate_power_curve_plot():
    """
    Generate a power curve plot based on the power analysis results.
    
    This function reads the target sample size and simulated power data
    from the power analysis results and creates a visualization showing
    how statistical power increases with sample size.
    
    Outputs:
        data/processed/power_curve.png: The generated power curve plot
    """
    results = load_power_analysis_results()
    
    # Extract data from results
    target_n = results.get('target_sample_size', 0)
    simulation_data = results.get('simulation_data', {})
    
    sample_sizes = simulation_data.get('sample_sizes', [])
    powers = simulation_data.get('powers', [])
    
    if not sample_sizes or not powers:
        raise ValueError(
            "No simulation data found in power analysis results. "
            "Ensure T009 generated valid simulation_data."
        )
    
    # Create the plot
    plt.figure(figsize=(10, 6))
    plt.plot(sample_sizes, powers, 'b-', linewidth=2, marker='o', markersize=4)
    plt.axhline(y=0.80, color='r', linestyle='--', label='Target Power (0.80)')
    plt.axvline(x=target_n, color='g', linestyle='--', 
               label=f'Target N = {target_n}')
    
    # Highlight the target point
    if target_n in sample_sizes:
        idx = sample_sizes.index(target_n)
        plt.scatter([target_n], [powers[idx]], color='orange', 
                   s=100, zorder=5, label=f'Power at N={target_n}: {powers[idx]:.2f}')
    
    plt.xlabel('Sample Size (N)', fontsize=12)
    plt.ylabel('Statistical Power', fontsize=12)
    plt.title('Power Curve for LMM Interaction Effect', fontsize=14)
    plt.legend(loc='lower right')
    plt.grid(True, alpha=0.3)
    plt.ylim(0, 1.05)
    plt.xlim(0, max(sample_sizes) * 1.1 if sample_sizes else 100)
    
    # Ensure output directory exists
    figures_dir = get_figures_dir()
    figures_dir.mkdir(parents=True, exist_ok=True)
    
    output_path = figures_dir / "power_curve.png"
    plt.savefig(output_path, dpi=300, bbox_inches='tight')
    plt.close()
    
    print(f"Power curve plot saved to: {output_path}")
    return output_path

def main():
    """Main entry point for the power curve plotter."""
    try:
        output_path = generate_power_curve_plot()
        print(f"Successfully generated power curve at {output_path}")
    except Exception as e:
        print(f"Error generating power curve: {e}")
        raise

if __name__ == "__main__":
    main()
